VALUES
  ('social-worker-moex-01371', 'social-worker', 'social-worker-moex-109-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關反映（reflection）技術中的「內容反映」，下列敘述何者正確？①是選擇問題的關鍵、關係', '["領導者表達體會 成員感受的心意，也就是「設身處地」、「感同身受」、「將心比心」", "內容反映的執行成效 可概略分為無效的重述、沒有影響力的重述、有效的重述", "最早是由Carl Rogers提出，其認 為助人者應該像一面鏡子，忠實、沒有評價地讓個案聽見自己所說的內容 ⑤領導者用較少的語 言重複或重述成員所說的內容與意義", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "e697d89d6b44", "answer_pdf_sha1": "6638e1fe6f90", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 25, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01372', 'social-worker', 'social-worker-moex-109-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社區工作者需先進行深入的問題分析及資料蒐集，進而以最理性的方式進行社區策略擬定，此為 Rothman主張的那一種工作模式？', '["地區發展模式", "社會計畫模式", "社會行動模式", "社會變遷模式"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "e697d89d6b44", "answer_pdf_sha1": "6638e1fe6f90", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01373', 'social-worker', 'social-worker-moex-109-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關「知後同意」（informedconsent）的敘述，下列何者錯誤？', '["「知後同意」是常見的團體成員權益之一", "「知後同意」需要團體工作者告知成員其所參加的處遇與其他相關的訊息", "「知後同意」被視為一個專有的名詞，「告知」和「同意」二個詞彙因此不需分開考量", "「知後同意」係指成員有權利知道其與團體領導者的任務分配，以及這段助人過程的目的與性質"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "e697d89d6b44", "answer_pdf_sha1": "6638e1fe6f90", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01374', 'social-worker', 'social-worker-moex-109-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '團體領導者須遵循倫理規範，以確保團體成員不會受到過度壓力，下列何者錯誤？', '["團體成員有不參加的自由，但若團體領導者認為成員會因參加團體而受益，其將考驗領導者如 何在適當的挑戰、適當的壓力及適當的倫理中找到平衡", "團體領導者對於團體成員自行決定要探索什麼，及要進行到什麼程度，給予基本的尊重", "團體領導者可能在活動中觸摸成員，必須要很謹慎，並清楚解釋為何觸摸，並可在團體中帶入 這個主題的討論，以確定成員的隱私或是界線未被侵犯", "有時適當的情緒宣洩是必要的，但僅需要向其他成員釐清此情緒宣洩是為了滿足特定成員的需要"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "e697d89d6b44", "answer_pdf_sha1": "6638e1fe6f90", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01375', 'social-worker', 'social-worker-moex-109-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '「社區意識」這個概念是由熟悉感、認同感、歸屬感及榮譽感四個部分所組成，下列敘述何者錯誤？', '["熟悉感是四個部分之最末端，有認同感及歸屬感，自然而然就會對社區產生一定的熟悉度", "在正向的歸屬感中會產生認同感", "歸屬感與認同感均屬於團體內的自發感情", "歸屬感與認同感的共同作用，加上外部團體的肯定，則會產生榮譽感"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "e697d89d6b44", "answer_pdf_sha1": "6638e1fe6f90", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01376', 'social-worker', 'social-worker-moex-109-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '在地區產業發展中可能產生的矛盾，下列何者錯誤？', '["社區產業發展與經濟發展的衝突", "社區產業發展中獲利者與承擔者的問題", "地區產業發展中的競爭與合作問題", "社區發展模式與經濟發展模式的矛盾"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "e697d89d6b44", "answer_pdf_sha1": "6638e1fe6f90", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01377', 'social-worker', 'social-worker-moex-109-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '在「聯合社區」的工作模式中，促進協力社區與領航社區之共事合作及進行社區觀摩交流，符合 下列那一項發展原則？', '["優勢觀點", "學習型組織", "專業協助", "公私部門夥伴關係"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "e697d89d6b44", "answer_pdf_sha1": "6638e1fe6f90", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01378', 'social-worker', 'social-worker-moex-109-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '透過一定的程序及步驟來引導並達成社區的改變，以解決社區問題，此為那一個工作理論之核心 看法？', '["任務中心與任務團體理論", "資源動員與交換理論", "權力與培力理論", "社會計畫與變遷理論"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "e697d89d6b44", "answer_pdf_sha1": "6638e1fe6f90", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01379', 'social-worker', 'social-worker-moex-109-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社區需求調查方法中，透過政府既有的社會與公共衛生統計數據來認識社區，對社區人口、社會 結構有基本的了解，屬於下列何種社區需求調查方法？', '["服務需求法", "服務提供與資源分析法", "社會與健康指標分析法", "德菲法"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "e697d89d6b44", "answer_pdf_sha1": "6638e1fe6f90", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01380', 'social-worker', 'social-worker-moex-109-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關社區印象法（communityimpressions）的敘述，下列何者正確？', '["透過公共集會的方式，以互動的方法，收集社區居民需求的資訊", "透過召集各社區、各團體的代表，以收集有關社區的資訊", "以社區意見領袖為對象，一再向社區領袖請益與釐清相關問題，收集社區需求的資訊", "結合社區的資訊、意見領袖的訪談、社區居民的訪談及實地的踏勘，而獲得社區綜合需求的方法"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "e697d89d6b44", "answer_pdf_sha1": "6638e1fe6f90", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
